#!/usr/bin/env python3
from __future__ import annotations
import base64, csv, gzip, hashlib, io, json, pathlib, urllib.request
ROOT=pathlib.Path(__file__).resolve().parent
SOURCE_URL='https://raw.githubusercontent.com/scrollmapper/bible_databases/master/formats/csv/JapKougo.csv'
EXPECTED_GIT_BLOB_SHA1='48531f60873541ce928be6d2b31ec832686a75ca'
def git_blob_sha1(raw: bytes)->str:
    return hashlib.sha1(f"blob {len(raw)}\0".encode()+raw).hexdigest()
def main():
    src=ROOT/'JapKougo.csv'; urllib.request.urlretrieve(SOURCE_URL,src)
    raw=src.read_bytes(); blob=git_blob_sha1(raw)
    if blob!=EXPECTED_GIT_BLOB_SHA1: raise SystemExit(f'Pinned source mismatch: {blob}')
    index={}
    with src.open(encoding='utf-8-sig',newline='') as f:
        for row in csv.DictReader(f): index[(row['Book'],int(row['Chapter']),int(row['Verse']))]=row['Text']
    cards=[]; missing=[]
    selected_csv=gzip.decompress(base64.b64decode('''''')).decode('utf-8')
    with io.StringIO(selected_csv,newline='') as f:
        for row in csv.DictReader(f):
            parts=[]
            for v in range(int(row['start_verse']),int(row['end_verse'])+1):
                t=index.get((row['book_name_en'],int(row['chapter']),v))
                if t is None: missing.append([row['id'],row['book_name_en'],row['chapter'],v])
                else: parts.append(t)
            text=' '.join(parts); cards.append({'id':row['id'],'text':text,'sha256':hashlib.sha256(text.encode()).hexdigest(),'verseCount':len(parts)})
    if missing: raise SystemExit(f'Missing verses: {missing[:20]} total={len(missing)}')
    result={'source':{'url':SOURCE_URL,'gitBlobSha1':blob,'fileSha256':hashlib.sha256(raw).hexdigest(),'bytes':len(raw),'license':'Public Domain per repository source README'},'cardCount':len(cards),'cards':cards}
    (ROOT/'japanese-selected.json').write_text(json.dumps(result,ensure_ascii=False,indent=2),encoding='utf-8')
    (ROOT/'BUILD_REPORT.txt').write_text(f"PASS\nsource_git_blob_sha1={blob}\nsource_sha256={result['source']['fileSha256']}\ncards={len(cards)}\n",encoding='utf-8')
if __name__=='__main__': main()
